// Node.js — agent loop with instruction/task separation
import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic();

const SYSTEM = `
You are a research orchestrator sub-agent.
Rules:
- Use the search_web tool only when the task explicitly says SEARCH.
- Return your result as a JSON object: {"result": <value>, "done": true|false}.
- "done": true means the orchestrator should stop the loop.
`;

function buildTask(stepName, payload) {
  return `Task: ${stepName}\n\nInput:\n${JSON.stringify(payload, null, 2)}`;
}

async function agentLoop(steps) {
  const messages = [];
  let lastResult = null;

  for (const step of steps) {
    const task = buildTask(step.name, { ...step.input, previousResult: lastResult });
    messages.push({ role: 'user', content: task });

    const resp = await client.messages.create({
      model: 'claude-opus-4-5',
      max_tokens: 512,
      system: SYSTEM,
      messages,
    });

    const text = resp.content[0].text;
    messages.push({ role: 'assistant', content: text });
    const parsed = JSON.parse(text);
    lastResult = parsed.result;

    if (parsed.done) break;
  }
  return lastResult;
}

// SYSTEM never changes; each step injects a new task.
// The orchestrator drives the loop, not the model.
